```python
import pytest

def zip_dicts(*dicts) -> dict:
    keys = set().union(*dicts)
    return {k: [d.get(k) for d in dicts] for k in keys}


class TestZipDicts:
    """Unit tests for zip_dicts function."""

    # ==================== HAPPY PATH ====================
    def test_overlapping_keys(self):
        """Standard case with partial key overlap."""
        result = zip_dicts({'a': 1, 'b': 2}, {'b': 3, 'c': 4})
        assert result == {'a': [1, None], 'b': [2, 3], 'c': [None, 4]}

    def test_all_keys_overlap(self):
        """All dictionaries share the exact same keys."""
        result = zip_dicts({'x': 10}, {'x': 20}, {'x': 30})
        assert result == {'x': [10, 20, 30]}

    def test_no_overlapping_keys(self):
        """Dictionaries have completely disjoint keys."""
        result = zip_dicts({'a': 1}, {'b': 2}, {'c': 3})
        assert result == {'a': [1, None, None], 'b': [None, 2, None], 'c': [None, None, 3]}

    def test_mixed_value_types(self):
        """Values can be of any hashable type."""
        result = zip_dicts({'k': 'str'}, {'k': 123}, {'k': [1, 2]})
        assert result == {'k': ['str', 123, [1, 2]]}

    # ==================== EDGE CASES ====================
    def test_no_arguments(self):
        """Calling with zero arguments returns an empty dict."""
        assert zip_dicts() == {}

    def test_single_empty_dict(self):
        """Single empty dictionary input."""
        assert zip_dicts({}) == {}

    def test_multiple_empty_dicts(self):
        """Multiple empty dictionaries input."""
        assert zip_dicts({}, {}, {}) == {}

    def test_explicit_none_values(self):
        """Explicit None values are preserved (indistinguishable from missing keys)."""
        result = zip_dicts({'a': None}, {'a': 1})
        assert result == {'a': [None, 1]}

    def test_non_string_keys(self):
        """Keys can be integers, tuples, or other hashable types."""
        result = zip_dicts({1: 'one', (2, 3): 'tuple'}, {1: 'ONE', 4: 'four'})
        assert result == {1: ['one', 'ONE'], (2, 3): ['tuple', None], 4: [None, 'four']}

    def test_original_dicts_unchanged(self):
        """Function should not mutate input dictionaries."""
        d1 = {'a': 1}
        d2 = {'a': 2}
        zip_dicts(d1, d2)
        assert d1 == {'a': 1}
        assert d2 == {'a': 2}

    # ==================== ERROR CASES ====================
    def test_non_dict_input_raises_attribute_error(self):
        """Passing a non-dict iterable (e.g., list) fails when .get() is called."""
        with pytest.raises(AttributeError):
            zip_dicts({'a': 1}, [1, 2])

    def test_non_iterable_input_raises_type_error(self):
        """Passing a non-iterable (e.g., int) fails during set union."""
        with pytest.raises(TypeError):
            zip_dicts({'a': 1}, 123)

    def test_mixed_valid_invalid_inputs(self):
        """Mix of dicts and invalid types raises an appropriate error."""
        with pytest.raises((AttributeError, TypeError)):
            zip_dicts({'a': 1}, "not a dict", {'b': 2})
